+    std::deque<typename mpl::at_c<Events, i>::type>& deque = boost::get<i>(deques_);
+    ROS_ASSERT(!deque.empty());
+    deque.pop_front();
+    if (deque.empty())
+    {
+      --num_non_empty_deques_;
+    }
+  }
+
+  // Assumes that deque number <index> is non empty
+  void dequeDeleteFront(uint32_t index)
