+    boost::get<1>(past_).clear();
+    boost::get<2>(past_).clear();
+    boost::get<3>(past_).clear();
+    boost::get<4>(past_).clear();
+    boost::get<5>(past_).clear();
+    boost::get<6>(past_).clear();
+    boost::get<7>(past_).clear();
