+  Chain<Msg> c;
+  c.addFilter(PassThroughPtr(new PassThrough<Msg>));
+  c.addFilter(PassThroughPtr(new PassThrough<Msg>));
+  c.addFilter(PassThroughPtr(new PassThrough<Msg>));
