+TEST(ExactTime, queueSize)
+{
+  Sync3 sync(1);
+  Helper h;
+  sync.registerCallback(boost::bind(&Helper::cb, &h));
+  MsgPtr m(new Msg);
+  m->header.stamp = ros::Time();
+
+  sync.add<0>(m);
+  ASSERT_EQ(h.count_, 0);
+  sync.add<1>(m);
+  ASSERT_EQ(h.count_, 0);
+
+  m.reset(new Msg);
+  m->header.stamp = ros::Time(0.1);
+  sync.add<1>(m);
+  ASSERT_EQ(h.count_, 0);
+
+  m.reset(new Msg);
+  m->header.stamp = ros::Time(0);
+  sync.add<1>(m);
+  ASSERT_EQ(h.count_, 0);
+  sync.add<2>(m);
+  ASSERT_EQ(h.count_, 0);
+}
+
+TEST(ExactTime, dropCallback)
+{
+  Sync2 sync(1);
+  Helper h;
+  sync.registerCallback(boost::bind(&Helper::cb, &h));
